(window.webpackJsonp=window.webpackJsonp||[]).push([[177],{804:function(n,t){n.exports='\x3c!-- \ntitle: 00-Python配置\nsort: \n--\x3e \n\n> [Anaconda](https://mirrors.tuna.tsinghua.edu.cn/anaconda/archive/?C=M&O=D)\n\n## Conda\n\n### 换源\n\n> 生成配置文件: `conda config --set show_channel_urls yes`\n>\n> 清除索引缓存: `conda clean -i`\n\n```python\n# .condarc\nchannels:\n  - defaults\nshow_channel_urls: true\ndefault_channels:\n  - https://anaconda.mirrors.sjtug.sjtu.edu.cn/pkgs/r\n  - https://anaconda.mirrors.sjtug.sjtu.edu.cn/pkgs/main\ncustom_channels:\n  conda-forge: https://anaconda.mirrors.sjtug.sjtu.edu.cn/cloud/\n  pytorch: https://anaconda.mirrors.sjtug.sjtu.edu.cn/cloud/\n\n# 代理设置\nproxy_servers:\n  http: http://127.0.0.1:7890\n  https: https://127.0.0.1:7890\nssl_verify: false\n```\n\n> 虚拟环境\n\n```powershell\nconda env list\n\nconda create -n <name>\nconda remove -n <name> --all\nconda init <shell_name>\n# restart shell\n\nconda activate <name>\nconda deactivate\n\n# 进入环境\nconda init\nconda deactivate\n# 默认不启动/启动\nconda config --set auto_activate_base false\nconda config --set auto_activate_base true\n# 清除缓存包\nconda clean --packages --tarballs\n```\n\n> 实战\n\n```python\nconda create -n learn-pytorch\n# 重命名\nconda create -n ltorch --clone conda remove -n <name> --all\nconda remove -n learn-pytorch --all\n```\n\n### 问题\n\n> ==powershell==\n>\n> `在此系统上禁止运行脚本 profile.ps1`\n\n```bash\nSet-ExecutionPolicy -ExecutionPolicy RemoteSigned\n```\n\n> ==cmd==\n>\n> `脚本加载失败`\n\n## Python换源\n\n> `pip install -i https://pypi.tuna.tsinghua.edu.cn/simple <name>`\n>\n> `pip config set global.index-url https://pypi.tuna.tsinghua.edu.cn/simple`\n\n### windows\n\n- 在user目录中创建一个pip目录，如：C:\\Users\\xx\\pip\n- 然后新建文件pip.ini，即 %HOMEPATH%\\pip\\pip.ini\n\n- 在pip.ini中输入以下内容：\n\n  ```ini\n  [global]\n  index-url = https://pypi.tuna.tsinghua.edu.cn/simple\n  \n  # 报错添加如下行\n  trusted-host=pypi.tuna.tsinghua.edu.cn\n  ```\n  \n\n### Linux\n\n#### **修改本用户**\n\n- 修改 ： ~/.pip/pip.conf\n\n  `注： 没有就创建一个文件夹及文件。文件夹要加“.”，表示是隐藏文件夹。`\n\n\n- 在pip.conf中输入以下内容：\n\n  ```ini\n  [global]\n  index-url = https://pypi.tuna.tsinghua.edu.cn/simple\n  ```\n\n- 修改root账户：\n\n  ```bash\n  sudo pip config set global.index-url https://pypi.tuna.tsinghua.edu.cn/simple\n  ```\n  \n\n#### 系统修改\n\n- 修改`/etc/pip.conf`\n\n## 批量安装第三方库\n\n> `pip freeze > requirements.txt`生成当前配置文件\n\n```python\nimport os\n\nlibs = []\n\ntry:\n    for lib in libs:\n        os.system("pip install " + lib)\n    print("安装成功")\nexcept:\n    print("安装失败")\n\n```\n\n## 虚拟环境\n\n> 创建一个与外界隔绝的python环境\n>\n> `virtualenv`\n\n```bash\npip install virtualenv\nvirtualenv <env_name>\ncd <env_name>\n# 进入\n./bin/active\n```\n\n> `virtualenvwrapper`\n>\n> 方便管理虚拟环境\n\n```bash\npip install virtualenvwrapper\nmkvirtualenv --python=<python_path> <name>\n# 管理\nworkon <name>\t# 进入\nrmvirtualenv <name>\t# 删除\ndeactivate\t# 退出\n# 列表\nlsvirtualenv <name>\n# 进入目录\ncdvirtualenv demo\n```\n'}}]);